ansparent;\" align=\"center\"><span class=\"27pt\"><span style=\"font-size: 7.0pt;\">3</span></span></p>\r\n</td>\r\n<td style=\"width: 100.3pt; border: none; border-left: solid windowtext 1.0pt; mso-border-left-alt: solid windowtext .5pt; background: white; padding: 0cm .5pt 0cm .5pt; height: 10.8pt; mso-height-rule: exactly;\" valign=\"top\" width=\"134\">\r\n<p class=\"20\" style=\"text-align: justify; text-indent: 0cm; line-height: 7.0pt; mso-line-height-rule: exactly; background: transparent;\"><span class=\"27pt\"><span style=\"font-size: 7.0pt;\">3 (переменный)</span></span></p>\r\n</td>\r\n<td style=\"width: 198.95pt; border-top: none; border-left: solid windowtext 1.0pt; border-bottom: none; border-right: solid windowtext 1.0pt; mso-border-left-alt: solid windowtext .5pt; mso-border-right-alt: solid windowtext .5pt; background: white; padding: 0cm .5pt 0cm .5pt; height: 10.8pt; mso-height-rule: exactly;\" valign=\"top\" width=\"265\">\r\n<p class=\"20\" style=\"text-indent: 0cm; line-height: 7.0pt; mso-line-height-rule: exactly; background: transparent;\"><span class=\"27pt\"><span style=\"font-size: 7.0pt;\">Вариант по таблице 5: 250, 400, 630, 1000 А</span></span></p>\r\n</td>\r\n</tr>\r\n<tr style=\"mso-yfti-irow: 3; height: 11.75pt; mso-height-rule: exactly;\">\r\n<td style=\"width: 25.45pt; border-top: solid windowtext 1.0pt; border-left: solid windowtext 1.0pt; border-bottom: none; border-right: none; mso-border-top-alt: solid windowtext .5pt; mso-border-left-alt: solid windowtext .5pt; background: white; padding: 0cm .5pt 0cm .5pt; height: 11.75pt; mso-height-rule: exactly;\" valign=\"bottom\" width=\"34\">\r\n<p class=\"20\" style=\"text-align: center; text-indent: 0cm; line-height: 7.0pt; mso-line-height-rule: exactly; background: transparent;\" align=\"center\"><span class=\"27pt\"><span style=\"font-size: 7.0pt;\">4</span></span></p>\r\n</td>\r\n<td style=\"width: 100.3pt; border-top: solid windowtext 1.0pt; border-left: solid windowtext 1.0pt; border-bottom: none; border-right: none; mso-border-top-alt: solid windowtext .5pt; mso-border-left-alt: solid windowtext .5pt; background: white; padding: 0cm .5pt 0cm .5pt; height: 11.75pt; mso-height-rule: exactly;\" valign=\"bottom\" width=\"134\">\r\n<p class=\"20\" style=\"text-align: justify; text-indent: 0cm; line-height: 7.0pt; mso-line-height-rule: exactly; background: transparent;\"><span class=\"27pt\"><span style=\"font-size: 7.0pt;\">2 (постоянный)</span></span></p>\r\n</td>\r\n<td style=\"width: 198.95pt; border: solid windowtext 1.0pt; border-bottom: none; mso-border-top-alt: solid windowtext .5pt; mso-border-left-alt: solid windowtext .5pt; mso-border-right-alt: solid windowtext .5pt; background: white; padding: 0cm .5pt 0cm .5pt; height: 11.75pt; mso-height-rule: exactly;\" valign=\"bottom\" width=\"265\">\r\n<p class=\"20\" style=\"text-indent: 0cm; line-height: 7.0pt; mso-line-height-rule: exactly; background: transparent;\"><span class=\"27pt\"><span style=\"font-size: 7.0pt;\">Вариант по таблице 5: 250, 400, 630 А</span></span></p>\r\n</td>\r\n</tr>\r\n<tr style=\"mso-yfti-irow: 4; mso-yfti-lastrow: yes; height: 11.5pt; mso-height-rule: exactly;\">\r\n<td style=\"width: 25.45pt; border-top: none; border-left: solid windowtext 1.0pt; border-bottom: solid windowtext 1.0pt; border-right: none; mso-border-left-alt: solid windowtext .5pt; mso-border-bottom-alt: solid windowtext .5pt; background: white; padding: 0cm .5pt 0cm .5pt; height: 11.5pt; mso-height-rule: exactly;\" width=\"34\">\r\n<p class=\"20\" style=\"text-align: center; text-indent: 0cm; line-height: 7.0pt; mso-line-height-rule: exactly; background: transparent;\" align=\"center\"><span class=\"27pt\"><span style=\"font-size: 7.0pt;\">8</span></span></p>\r\n</td>\r\n<td style=\"width: 100.3pt; border-top: none; border-left: solid windowtext 1.0pt; border-bottom: solid windowtext 1.0pt; border-right: none; mso-border-left-alt: solid windowtext .5pt; mso-border-bottom-alt: solid windowtext .5pt; background: white; padding: 0cm .5pt 0cm .5pt; height: 11.5pt; mso-height-rule: exactly;\" valign=\"top\" width=\"134\">\r\n<p class=\"20\" style=\"text-align: justify; text-indent: 0cm; line-height: 7.0pt; mso-line-height-rule: exactly; background: transparent;\"><span class=\"27pt\"><span style=\"font-size: 7.0pt;\">2 (постоянный)</span></span></p>\r\n</td>\r\n<td style=\"width: 198.95pt; border: solid windowtext 1.0pt; border-top: none; mso-border-left-alt: solid windowtext .5pt; mso-border-bottom-alt: solid windowtext .5pt; mso-border-right-alt: solid windowtext .5pt; background: white; padding: 0cm .5pt 0cm .5pt; height: 11.5pt; mso-height-rule: exactly;\" valign=\"top\" width=\"265\">\r\n<p class=\"20\" style=\"text-indent: 0cm; line-height: 7.0pt; mso-line-height-rule: exactly; background: transparent;\"><span class=\"27pt\"><span style=\"font-size: 7.0pt;\">Вариант по таблице 5: 250, 400, 630, 1000 А</span></span></p>\r\n</td>\r\n</tr>\r\n</table>\r\n<p class=\"MsoNormal\">&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;Х Условное обозначение вида максимального расцепителя тока и вида защит:</p>\r\n<p class=\"MsoNormal\" style=\"text-indent: 35.45pt;\">0 - без максимальных расцепителей тока (для выключателей ВА56);</p>\r\n<p class=\"MsoNormal\" style=\"text-indent: 35.45pt;\">2 - электромагнитные расцепители с защитой от тока короткого замыкания (для выключателей ВА52);</p>\r\n<p class=\"MsoNormal\" style=\"text-indent: 35.45pt;\">3 - электронный микропроцессорный максимальный расцепитель тока МРТ1-МП для защиты от токов перегрузки, короткого замыкания, однофазного короткого замыкания, защитой по каналу КЗ без выдержки времени и токов включения для выключателей ВА53, ВА55 переменного тока;</p>\r\n<p class=\"MsoNormal\" style=\"text-indent: 35.45pt;\">4 - электронный микропроцессорный максимальный расцепитель тока МРТ2-МП для защиты от токов перегрузки, короткого замыкания, защитой по каналу КЗ без выдержки времени и токов включения для выключателей ВА53, ВА55 переменного тока;</p>\r\n<p class=\"MsoNormal\" style=\"text-indent: 35.45pt;\">5 - электронный максимальный расцепитель тока МРТ6 для защиты от токов перегрузки и короткого замыкания для выключателей ВА53, ВА55 постоянного тока (выдержки времени: мгн., 0,1, 0,2, 0,3 с);</p>\r\n<p class=\"MsoNormal\" style=\"text-indent: 35.45pt;\">6 - электронный максимальный расцепитель тока МРТ8 для защиты от токов перегрузки и короткого замыкания для выключателей ВА53, ВА55 постоянного тока (выдержки времени: мгн., 0,2, 0,4, 0,6 с);</p>\r\n<p class=\"MsoNormal\" style=\"text-indent: 35.45pt;\">7 - электронный (микропроцессорный) максимальный расцепитель тока МРТ4-МП для защиты от токов перегрузки, короткого замыкания и токов включения для выключателей ВА53, ВА55 переменного тока</p>\r\n<p>&nbsp;</p>\r\n<p class=\"MsoNormal\" style=\"text-indent: 35.45pt;\">ХХ Обозначение исполнения по дополнительным расцепителям и вспомогательным контактам по таблице 2</p>\r\n<p class=\"MsoNormal\" style=\"text-indent: 35.45pt;\"><img src=\"https://plato-intel.by/storage/uploads/blobid1.png\" alt=\"\" /></p>\r\n<p class=\"MsoNormal\" style=\"text-indent: 35.45pt;\">Х Условное обозначение исполнения вида привода в сочетании со способом установки выключателя:</p>\r\n<p class=\"MsoNormal\" style=\"text-indent: 35.45pt;\">1 - ручной привод, стационарное исполнение;</p>\r\n<p class=\"MsoNormal\" style=\"text-indent: 35.45pt;\">3 - электромагнитный привод, стационарное исполнение;</p>\r\n<p class=\"MsoNormal\" style=\"text-indent: 35.45pt;\">5 - ручной дистанционный привод, выдвижное исполнение;</p>\r\n<p class=\"MsoNormal\" style=\"text-indent: 35.45pt;\">7 - электромагнитный привод, выдвижное исполнение</p>\r\n<p class=\"MsoNormal\" style=\"text-indent: 35.45pt;\">Х Цифра. Условное обозначение исполнения по дополнительным механизмам:</p>\r\n<p class=\"MsoNormal\" style=\"text-indent: 35.45pt;\">0 - отсутствуют;</p>\r\n<p class=\"MsoNormal\" style=\"text-indent: 35.45pt;\">5 - механизм для оперирования через дверь распредустройства выключателем стационарного исполнения с ручным приводом;</p>\r\n<p class=\"MsoNormal\" style=\"text-indent: 35.45pt;\">6 - устройство для блокировки положений &laquo;включено&raquo; и &laquo;отключено&raquo; выключателя стационарного исполнения;</p>\r\n<p class=\"MsoNormal\" style=\"text-indent: 35.45pt;\">7 - узел для установки электромагнитного замка у выключателей выдвижного исполнения;</p>\r\n<p class=\"MsoNormal\" style=\"text-indent: 35.45pt;\">8 - узел для установки электромагнитного замка и выключателей сигнализации конечных положений выключателей выдвижного исполнения</p>\r\n<p class=\"MsoNormal\" style=\"text-indent: 35.45pt;\">ХХ Условное обозначение исполнения по степени защиты:</p>\r\n<p class=\"MsoNormal\" style=\"text-indent: 35.45pt;\">20 - IP20;</p>\r\n<p class=\"MsoNormal\" style=\"text-indent: 35.45pt;\">00 - IP00</p>\r\n<p class=\"MsoNormal\" style=\"text-indent: 35.45pt;\">&nbsp;</p>\r\n<p class=\"MsoNormal\" style=\"text-indent: 35.45pt;\">ХХХХ Условное обозначение климатического исполнения: УХЛ3, Т3</p>\r\n<p>&nbsp;</p>',100,1,'2025-10-08 09:24:13','2025-10-08 09:28:44',NULL,0),(218,'тестовая',NULL,'testovaya',NULL,'<p><img src=\"/storage/uploads/тех А3790.jpg\" width=\"1040\" height=\"617\" alt=\"\" /></p>',100,0,'2025-10-08 09:41:55','2025-10-08 09:41:55',NULL,0),(219,'Кабели крановые',NULL,'kabeli-kranovye','categories/February2026/GpJZCtLdtP06w9ej6wa6.jpg',NULL,100,0,'2026-02-11 08:02:59','2026-02-11 08:02:59',NULL,0);
